def json_response(data: Any, status: int = 200, headers: Optional[Dict[str, str]] = None) -> Response:
    resp = Response(
        response=json.dumps(data, ensure_ascii=False, separators=(",", ":")),
        status=status,
        mimetype="application/json",
    )
    if headers:
        for k, v in headers.items():
            resp.headers[k] = v
    return resp


